import { Router } from "express";

const router = Router();

interface TestBody {
  baseUrl: string;
  apiKey?: string;
  modelName: string;
  provider: string;
}

interface TestResult {
  success: boolean;
  latencyMs: number;
  model?: string;
  sample?: string;
  error?: string;
}

// POST /api/model-settings/test
router.post("/test", async (req, res) => {
  const { baseUrl, apiKey, modelName, provider } = req.body as TestBody;

  if (!baseUrl || !modelName) {
    return res.status(400).json({ error: "baseUrl and modelName are required" });
  }

  const start = Date.now();

  try {
    // Normalise trailing slash
    const base = baseUrl.replace(/\/$/, "");
    const endpoint = `${base}/chat/completions`;

    const headers: Record<string, string> = { "Content-Type": "application/json" };
    if (apiKey) headers["Authorization"] = `Bearer ${apiKey}`;

    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 8_000);

    let r: Response;
    try {
      r = await fetch(endpoint, {
        method: "POST",
        headers,
        body: JSON.stringify({
          model: modelName,
          messages: [{ role: "user", content: "Hi" }],
          max_tokens: 5,
          stream: false,
        }),
        signal: controller.signal,
      });
    } finally {
      clearTimeout(timer);
    }

    const latencyMs = Date.now() - start;

    if (!r.ok) {
      const body = await r.text().catch(() => "");
      const result: TestResult = {
        success: false,
        latencyMs,
        error: `HTTP ${r.status}: ${body.slice(0, 120)}`,
      };
      return res.json(result);
    }

    const json = (await r.json()) as {
      choices?: Array<{ message?: { content?: string } }>;
    };
    const sample = json?.choices?.[0]?.message?.content ?? "";
    const result: TestResult = {
      success: true,
      latencyMs,
      model: modelName,
      sample: sample.slice(0, 60),
    };
    return res.json(result);
  } catch (err: unknown) {
    const msg =
      err instanceof Error ? err.message : String(err);
    const result: TestResult = {
      success: false,
      latencyMs: Date.now() - start,
      error: msg.slice(0, 120),
    };
    return res.json(result);
  }
