const INTENT_LABELS: Record<string, string> = {
  "greeting":       "Greetings",
  "knowledge":      "Knowledge",
  "code":           "Code",
  "weather":        "Weather",
  "geo":            "Geography",
  "planning-broad": "Planning",
  "general":        "General",
  "thinking":       "Deep Think",
};

